import React, { useEffect, useState } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

export default function BrowsePage() {
  const { API } = useAuth();
  const [searchParams, setSearchParams] = useSearchParams();
  const [movies, setMovies] = useState([]);
  const [genres, setGenres] = useState([]);
  const [loading, setLoading] = useState(false);
  const [mobileFilterOpen, setMobileFilterOpen] = useState(false);

  const search = searchParams.get('search') || '';
  const sort = searchParams.get('sort') || 'popular';
  const genre = searchParams.get('genre') || 'All';
  const collection = searchParams.get('collection') || ''; // 'free' for free movies

  // Fetch genres from local streamable movies only
  useEffect(() => {
    axios.get(`${API}/movies/genres`, { params: { streamable: true } })
      .then((res) => {
        const localGenres = res.data || [];
        setGenres(localGenres.slice(0, 15));
      })
      .catch(() => {
        setGenres(['All']);
    });
  }, [API]);

  // Fetch movies based on filters
  useEffect(() => {
    setLoading(true);

    // Search local streamable movies only
    if (search) {
      axios
        .get(`${API}/movies`, { params: { search, sort, limit: 50, streamable: true } })
        .then((res) => setMovies((res.data.movies || []).filter((movie) => movie?.videoUrl)))
        .catch(() => setMovies([]))
        .finally(() => setLoading(false));
      return;
    }

    // Show Free Movies collection
    if (collection === 'free') {
      axios
        .get(`${API}/movies`, { params: { isFree: 'true', limit: 50, streamable: true } })
        .then((res) => setMovies((res.data.movies || []).filter((movie) => movie?.videoUrl)))
        .catch(() => setMovies([]))
        .finally(() => setLoading(false));
      return;
    }

    // For genre filtering, use local streamable movies only
    if (genre && genre !== 'All') {
      axios
        .get(`${API}/movies`, { params: { genre, sort, limit: 50, streamable: true } })
        .then((res) => setMovies((res.data.movies || []).filter((movie) => movie?.videoUrl)))
        .catch(() => setMovies([]))
        .finally(() => setLoading(false));
      return;
    }

    // Default: use local database with sorting
    const params = { sort, limit: 50, streamable: true };
    axios
      .get(`${API}/movies`, { params })
      .then((res) => setMovies((res.data.movies || []).filter((movie) => movie?.videoUrl)))
      .catch(() => setMovies([]))
      .finally(() => setLoading(false));
  }, [API, search, sort, genre, collection]);

  const setSort = (nextSort) => {
    const next = new URLSearchParams(searchParams);
    next.set('sort', nextSort);
    setSearchParams(next);
  };

  const setGenreFilter = (nextGenre) => {
    const next = new URLSearchParams(searchParams);
    next.set('genre', nextGenre);
    setSearchParams(next);
  };

  const toggleFreeMovies = () => {
    const next = new URLSearchParams(searchParams);
    if (collection === 'free') {
      next.delete('collection');
    } else {
      next.set('collection', 'free');
      next.delete('genre'); // Clear genre filter when viewing free movies
    }
    setSearchParams(next);
  };

  return (
    <main className="page" style={{ padding: '100px 24px 32px' }}>
      <div style={{ marginBottom: '32px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', flexWrap: 'wrap', gap: '16px' }}>
          <h1 className="section-title" style={{ marginBottom: 0 }}>Browse</h1>
        </div>

        {/* Sort Pills */}
        <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap', marginBottom: '20px' }}>
          <span style={{ fontSize: '0.85rem', textTransform: 'uppercase', letterSpacing: '1px', color: 'var(--text-dim)', alignSelf: 'center' }}>Sort by:</span>
          {['popular', 'rating', 'year'].map((item) => (
            <button
              key={item}
              className={`genre-pill ${sort === item ? 'active' : ''}`}
              onClick={() => setSort(item)}
              style={{ textTransform: 'capitalize' }}
            >
              {item === 'popular' ? '🔥 Popular' : item === 'rating' ? '⭐ Rating' : '📅 Year'}
            </button>
          ))}
        </div>

        {/* Free Movies Collection */}
        <div style={{ marginBottom: '20px' }}>
          <h3 style={{ fontSize: '0.9rem', textTransform: 'uppercase', letterSpacing: '1px', color: 'var(--text-dim)', marginBottom: '12px' }}>Collections</h3>
          <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
            <button
              className={`genre-pill ${collection === 'free' ? 'active' : ''}`}
              onClick={toggleFreeMovies}
              style={{
                background: collection === 'free' ? 'var(--red)' : 'rgba(255, 255, 255, 0.1)',
                color: collection === 'free' ? '#fff' : 'var(--text)',
                border: collection === 'free' ? '1px solid var(--red)' : '1px solid var(--border)',
                borderRadius: 'var(--radius)',
                padding: '8px 16px',
                fontSize: '0.9rem',
                fontWeight: '600',
                cursor: 'pointer',
                transition: 'all 0.2s',
              }}
              onMouseEnter={(e) => {
                if (collection !== 'free') {
                  e.currentTarget.style.background = 'rgba(229, 9, 20, 0.2)';
                }
              }}
              onMouseLeave={(e) => {
                if (collection !== 'free') {
                  e.currentTarget.style.background = 'rgba(255, 255, 255, 0.1)';
                }
              }}
            >
              🎁 Free Movies
            </button>
          </div>
        </div>

        {/* Genre Filters */}
        <div style={{ marginBottom: '20px' }}>
          <h3 style={{ fontSize: '0.9rem', textTransform: 'uppercase', letterSpacing: '1px', color: 'var(--text-dim)', marginBottom: '12px' }}>Genre</h3>
          <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
            {genres.map((genreItem) => (
              <button
                key={genreItem}
                className={`genre-pill ${genre === genreItem ? 'active' : ''}`}
                onClick={() => setGenreFilter(genreItem)}
              >
                {genreItem}
              </button>
            ))}
          </div>
        </div>

        {/* Active Filters Display */}
        {(search || (genre && genre !== 'All') || collection === 'free') && (
          <div style={{ marginBottom: '20px', padding: '12px 16px', background: 'rgba(229, 9, 20, 0.1)', border: '1px solid rgba(229, 9, 20, 0.2)', borderRadius: 'var(--radius)' }}>
            <span style={{ fontSize: '0.85rem', color: 'var(--text-dim)' }}>Active filters: </span>
            {collection === 'free' && (
              <span style={{ display: 'inline-block', background: 'var(--red)', color: '#fff', padding: '2px 8px', borderRadius: '4px', fontSize: '0.8rem', marginRight: '8px' }}>
                🎁 Free Movies
              </span>
            )}
            {search && (
              <span style={{ display: 'inline-block', background: 'var(--red)', color: '#fff', padding: '2px 8px', borderRadius: '4px', fontSize: '0.8rem', marginRight: '8px' }}>
                Search: "{search}"
              </span>
            )}
            {genre && genre !== 'All' && (
              <span style={{ display: 'inline-block', background: 'var(--red)', color: '#fff', padding: '2px 8px', borderRadius: '4px', fontSize: '0.8rem' }}>
                Genre: {genre}
              </span>
            )}
          </div>
        )}
      </div>

      {loading ? (
        <div style={{ padding: '60px 20px', textAlign: 'center' }}>
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '16px' }}>
            <div className="spinner" />
            <p style={{ color: 'var(--text-dim)', fontSize: '0.95rem' }}>Loading movies...</p>
          </div>
        </div>
      ) : (
        <>
          <div style={{ marginBottom: '16px', color: 'var(--text-dim)', fontSize: '0.9rem' }}>
            Found <strong style={{ color: 'var(--text)' }}>{movies.length}</strong> {movies.length === 1 ? 'movie' : 'movies'}
          </div>
          <section style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))',
            gap: '16px'
          }}>
            {movies.length > 0 ? (
              movies.map((movie) => (
                <Link
                  key={movie._id}
                  to={`/movie/${movie._id}`}
                  className="movie-card"
                  style={{
                    height: '280px',
                    position: 'relative',
                    overflow: 'hidden',
                    borderRadius: 'var(--radius)'
                  }}
                >
                  <img src={movie.thumbnail} alt={movie.title} loading="lazy" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                  <div className="card-overlay">
                    <div className="card-title" style={{ fontSize: '1rem', fontWeight: '700', marginBottom: '8px' }}>{movie.title}</div>
                    <div style={{ display: 'flex', gap: '8px', alignItems: 'center', fontSize: '0.8rem', color: 'var(--text-dim)' }}>
                      <span>⭐ {movie.rating?.toFixed(1) || 'N/A'}</span>
                      <span>•</span>
                      <span>{movie.year}</span>
                    </div>
                  </div>
                </Link>
              ))
            ) : (
              <div className="empty-state" style={{ gridColumn: '1 / -1' }}>
                <div className="empty-state-icon">🎬</div>
                <div className="empty-state-title">No movies found</div>
                <div className="empty-state-desc">Try adjusting your filters or search terms</div>
              </div>
            )}
          </section>
        </>
      )}
    </main>
  );
}
